import pdfMake from "pdfmake/build/pdfmake.min.js";
import pdfFonts from "pdfmake/build/vfs_fonts.js";

pdfMake.vfs = pdfFonts.vfs;
const logoBase64='data:image/jpeg;base64,'

const safeArray = (arr) => Array.isArray(arr) ? arr : [];

// Pre-compress the logo to a small size so pdfMake doesn't hang rendering it on every page.
// The logo is 49KB — rendered in header+footer on every page, it freezes pdfMake's getBase64().
// We compress it once to ~5KB (80x80px JPEG) before any PDF generation.
let _compressedLogoBase64 = null;
const _logoReady = (async () => {
  try {
    const img = new Image();
    await new Promise((res, rej) => { img.onload = res; img.onerror = rej; img.src = logoBase64; });
    const canvas = document.createElement("canvas");
    const maxSide = 80;
    const scale = Math.min(1, maxSide / img.width, maxSide / img.height);
    canvas.width  = Math.max(1, Math.round(img.width  * scale));
    canvas.height = Math.max(1, Math.round(img.height * scale));
    const ctx = canvas.getContext("2d");
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    _compressedLogoBase64 = canvas.toDataURL("image/jpeg", 0.7);
  } catch {
    _compressedLogoBase64 = logoBase64;
  }
})();
 
